import{_ as e,o as a,c as i,ag as l}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Billing & Plans","description":"","frontmatter":{},"headers":[],"relativePath":"settings/billing.md","filePath":"settings/billing.md"}'),n={name:"settings/billing.md"};function r(s,t,o,d,g,p){return a(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="billing-plans" tabindex="-1">Billing &amp; Plans <a class="header-anchor" href="#billing-plans" aria-label="Permalink to &quot;Billing &amp; Plans&quot;">​</a></h1><p>Manage your MyCompanyDesk subscription, view usage, and upgrade your plan.</p><h2 id="plans" tabindex="-1">Plans <a class="header-anchor" href="#plans" aria-label="Permalink to &quot;Plans&quot;">​</a></h2><p>MyCompanyDesk offers three plans:</p><h3 id="free" tabindex="-1">Free <a class="header-anchor" href="#free" aria-label="Permalink to &quot;Free&quot;">​</a></h3><p>Get started at no cost:</p><ul><li>Limited invoices and customers</li><li>Basic expense tracking</li><li>Basic reports</li><li>1 user</li><li>Community support</li></ul><h3 id="pro" tabindex="-1">Pro <a class="header-anchor" href="#pro" aria-label="Permalink to &quot;Pro&quot;">​</a></h3><p>For growing businesses:</p><ul><li>Unlimited invoices and customers</li><li>Full expense tracking with receipt scanning</li><li>AI suggestions</li><li>Custom PDF branding</li><li>CSV export</li><li>Up to 5 team members</li><li>Email support</li></ul><h3 id="business" tabindex="-1">Business <a class="header-anchor" href="#business" aria-label="Permalink to &quot;Business&quot;">​</a></h3><p>For teams and scaling operations:</p><ul><li>Everything in Pro</li><li>Unlimited team members</li><li>API access</li><li>Priority support</li><li>Advanced integrations</li></ul><p>Plans are available in <strong>monthly</strong> and <strong>annual</strong> billing intervals. Annual plans include a discount.</p><h2 id="managing-your-subscription" tabindex="-1">Managing your subscription <a class="header-anchor" href="#managing-your-subscription" aria-label="Permalink to &quot;Managing your subscription&quot;">​</a></h2><h3 id="upgrade" tabindex="-1">Upgrade <a class="header-anchor" href="#upgrade" aria-label="Permalink to &quot;Upgrade&quot;">​</a></h3><ol><li>Go to <strong>Settings &gt; Billing</strong></li><li>Click <strong>Upgrade</strong> on the desired plan</li><li>Complete payment via Stripe</li><li>Features are activated immediately</li></ol><h3 id="downgrade" tabindex="-1">Downgrade <a class="header-anchor" href="#downgrade" aria-label="Permalink to &quot;Downgrade&quot;">​</a></h3><ol><li>Go to <strong>Settings &gt; Billing</strong></li><li>Click <strong>Change Plan</strong></li><li>Select the lower plan</li><li>Changes take effect at the end of the current billing period</li></ol><h3 id="cancel" tabindex="-1">Cancel <a class="header-anchor" href="#cancel" aria-label="Permalink to &quot;Cancel&quot;">​</a></h3><ol><li>Go to <strong>Settings &gt; Billing</strong></li><li>Click <strong>Manage Subscription</strong> to open the Stripe billing portal</li><li>Cancel your subscription</li><li>You retain access until the end of the paid period</li></ol><h2 id="usage-tracking" tabindex="-1">Usage tracking <a class="header-anchor" href="#usage-tracking" aria-label="Permalink to &quot;Usage tracking&quot;">​</a></h2><p>View your current usage on the billing page:</p><ul><li><strong>Invoices created</strong> this month</li><li><strong>Customers</strong> in your workspace</li><li><strong>Team members</strong> active</li><li><strong>API calls</strong> (Business plan)</li></ul><p>Usage resets monthly. If you approach a limit, you&#39;ll see a notification suggesting an upgrade.</p><h2 id="payment-methods" tabindex="-1">Payment methods <a class="header-anchor" href="#payment-methods" aria-label="Permalink to &quot;Payment methods&quot;">​</a></h2><p>Payments are processed securely through <strong>Stripe</strong>. Accepted methods:</p><ul><li>Credit card (Visa, Mastercard, Amex)</li><li>Debit card</li><li>SEPA direct debit (EU)</li></ul><p>Manage your payment method in the Stripe billing portal.</p><h2 id="billing-portal" tabindex="-1">Billing portal <a class="header-anchor" href="#billing-portal" aria-label="Permalink to &quot;Billing portal&quot;">​</a></h2><p>Click <strong>Manage Subscription</strong> to access the Stripe billing portal where you can:</p><ul><li>Update payment method</li><li>View invoice history</li><li>Download receipts</li><li>Change billing address</li></ul><h2 id="feature-entitlements" tabindex="-1">Feature entitlements <a class="header-anchor" href="#feature-entitlements" aria-label="Permalink to &quot;Feature entitlements&quot;">​</a></h2><p>Some features are gated by plan:</p><table tabindex="0"><thead><tr><th>Feature</th><th>Free</th><th>Pro</th><th>Business</th></tr></thead><tbody><tr><td>Custom branding</td><td>-</td><td>Yes</td><td>Yes</td></tr><tr><td>CSV export</td><td>-</td><td>Yes</td><td>Yes</td></tr><tr><td>Receipt scanning</td><td>-</td><td>Yes</td><td>Yes</td></tr><tr><td>AI suggestions</td><td>-</td><td>Yes</td><td>Yes</td></tr><tr><td>Text check</td><td>-</td><td>Yes</td><td>Yes</td></tr><tr><td>API access</td><td>-</td><td>-</td><td>Yes</td></tr></tbody></table><p>Attempting to use a gated feature on a lower plan shows an upgrade prompt.</p>',36)])])}const h=e(n,[["render",r]]);export{c as __pageData,h as default};
